import json
import os
import boto3
from botocore.exceptions import ClientError

sns = boto3.client("sns")

DEFAULT_TOPIC_ARN = os.environ.get("DEFAULT_TOPIC_ARN", "")


def _response(status_code, body):
    return {
        "statusCode": status_code,
        "headers": {"Content-Type": "application/json"},
        "body": json.dumps(body),
    }


def _extract_event_data(event):
    if isinstance(event, dict):
        if "body" in event and event["body"] is not None:
            body = event["body"]
            if isinstance(body, str):
                try:
                    body = json.loads(body)
                except json.JSONDecodeError:
                    body = {"message": body}
            elif not isinstance(body, dict):
                body = {"message": str(body)}
            return body
        return event
    return {"message": str(event)}


def _build_message(payload):
    notification_type = str(payload.get("notification_type", "default")).lower()
    message = payload.get("message", "")
    subject = payload.get("subject")
    attributes = payload.get("message_attributes", {})

    if notification_type == "json":
        if isinstance(message, (dict, list)):
            message = json.dumps(message)
        else:
            message = json.dumps({"message": message})
    elif notification_type == "alert":
        message = f"ALERT: {message}"
        if not subject:
            subject = "Alert Notification"
    elif notification_type == "info":
        message = f"INFO: {message}"
        if not subject:
            subject = "Information Notification"
    elif notification_type == "warning":
        message = f"WARNING: {message}"
        if not subject:
            subject = "Warning Notification"
    elif notification_type == "error":
        message = f"ERROR: {message}"
        if not subject:
            subject = "Error Notification"

    return message, subject, attributes


def _to_message_attributes(attributes):
    sns_attributes = {}
    if not isinstance(attributes, dict):
        return sns_attributes

    for key, value in attributes.items():
        if isinstance(value, dict) and "DataType" in value and "StringValue" in value:
            sns_attributes[key] = {
                "DataType": value["DataType"],
                "StringValue": str(value["StringValue"]),
            }
        else:
            if isinstance(value, bool):
                sns_attributes[key] = {"DataType": "String", "StringValue": str(value).lower()}
            elif isinstance(value, (int, float)):
                sns_attributes[key] = {"DataType": "Number", "StringValue": str(value)}
            else:
                sns_attributes[key] = {"DataType": "String", "StringValue": str(value)}
    return sns_attributes


def lambda_handler(event, context):
    payload = _extract_event_data(event)

    topic_arn = payload.get("topic_arn") or payload.get("TopicArn") or DEFAULT_TOPIC_ARN
    if not topic_arn:
        return _response(400, {"error": "topic_arn is required"})

    if "message" not in payload:
        return _response(400, {"error": "message is required"})

    message, subject, attributes = _build_message(payload)
    message_attributes = _to_message_attributes(attributes)

    publish_kwargs = {
        "TopicArn": topic_arn,
        "Message": message if isinstance(message, str) else json.dumps(message),
    }

    if subject:
        publish_kwargs["Subject"] = str(subject)[:100]

    if message_attributes:
        publish_kwargs["MessageAttributes"] = message_attributes

    try:
        result = sns.publish(**publish_kwargs)
        return _response(
            200,
            {
                "status": "published",
                "message_id": result.get("MessageId"),
                "topic_arn": topic_arn,
                "notification_type": str(payload.get("notification_type", "default")).lower(),
            },
        )
    except ClientError as e:
        return _response(
            500,
            {
                "error": "failed_to_publish",
                "details": e.response.get("Error", {}),
            },
        )
    except Exception as e:
        return _response(500, {"error": "unexpected_error", "details": str(e)})